diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 706cb828acc6..2c53271addb6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -4150,6 +4150,47 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     }
   }

+  /// For umul.with.overflow(X, C), the overflow condition is X > UINT_MAX / C.
+  /// The pattern "overflow | (X * C > K)" can be simplified to "X > K / C"
+  /// when K / C <= UINT_MAX / C (i.e., when the division does not overflow).
+  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
+                                        m_WithOverflowInst(WO), m_Value(WOV))),
+                                    m_Value(Ov)),
+                       m_OneUse(m_ICmp(Pred, m_ExtractValue<0>(m_Deferred(WOV)),
+                                       m_APInt(C2))))) &&
+      WO->getBinaryOp() == Instruction::Mul && !WO->isSigned() &&
+      ICmpInst::isUnsigned(Pred) && match(WO->getRHS(), m_APInt(C1)) &&
+      !C1->isZero()) {
+    // Compute NewC = C2 / C1 (unsigned floor division)
+    APInt NewC = C2->udiv(*C1);
+    // Check if the predicate is consistent with the overflow check.
+    // For UGT/UGE: overflow || (X * C > K)  --> X > K / C
+    // For ULT/ULE: overflow || (X * C < K)  --> X < ceil(K / C)
+    bool TransformValid = false;
+    if (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_UGE) {
+      TransformValid = true;
+    } else if (Pred == ICmpInst::ICMP_ULT || Pred == ICmpInst::ICMP_ULE) {
+      // For ULT/ULE: valid when K is a multiple of C
+      TransformValid = C2->urem(*C1).isZero();
+      if (TransformValid && Pred == ICmpInst::ICMP_ULT)
+        NewC = NewC + 1;
+    }
+    if (TransformValid) {
+      Value *NewCmp = Builder.CreateICmp(
+          Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
+      // If NewC <= UINT_MAX / C1, then overflow || (X * C > K) is equivalent
+      // to just X > NewC, because:
+      // - If X > UINT_MAX / C1, overflow occurs
+      // - If X <= UINT_MAX / C1, then X * C > K iff X > K / C = NewC
+      // Since NewC <= UINT_MAX / C1, the condition X > NewC implies X > UINT_MAX / C1
+      // is false, so overflow is false, and we just need X > NewC.
+      APInt MaxVal = APInt::getMaxValue(C1->getBitWidth());
+      if (NewC.ule(MaxVal.udiv(*C1)))
+        return replaceInstUsesWith(I, NewCmp);
+      return BinaryOperator::CreateOr(Ov, NewCmp);
+    }
+  }
+
   // (~x) | y  -->  ~(x & (~y))  iff that gets rid of inversions
   if (sinkNotIntoOtherHandOfLogicalOp(I))
     return &I;

